#include "biblia.h"

void Biblia::CarregarFilemon(Biblia* b) {
    b->dados[FILEMON].nome = wxT("Filemom");

    b->dados[FILEMON].capitulos[1].versos[1] = wxT("Paulo, prisioneiro de Cristo Jesus, e o irmão Timóteo, ao amado Filemom, nosso companheiro de trabalho,");
    b->dados[FILEMON].capitulos[1].versos[2] = wxT("e à nossa irmã Áfia, e a Arquipo, nosso companheiro de lutas, e à igreja que está em tua casa:");
    b->dados[FILEMON].capitulos[1].versos[3] = wxT("Graças a vós, e paz da parte de Deus nosso Pai, e do Senhor Jesus Cristo.");
    b->dados[FILEMON].capitulos[1].versos[4] = wxT("Sempre dou graças ao meu Deus, lembrando-me de ti nas minhas orações,");
    b->dados[FILEMON].capitulos[1].versos[5] = wxT("ao ouvir falar do amor e da fé que tens para com o Senhor Jesus e para com todos os santos;");
    b->dados[FILEMON].capitulos[1].versos[6] = wxT("para que a comunicação da tua fé se torne eficaz, no pleno conhecimento de todo o bem que em nós há para com Cristo.");
    b->dados[FILEMON].capitulos[1].versos[7] = wxT("Pois tive grande gozo e consolação no teu amor, porque por ti, irmão, os corações dos santos têm sido reanimados.");
    b->dados[FILEMON].capitulos[1].versos[8] = wxT("Pelo que, embora tenha em Cristo plena liberdade para te mandar o que convém,");
    b->dados[FILEMON].capitulos[1].versos[9] = wxT("todavia prefiro rogar-te por esse teu amor, sendo eu como sou, Paulo o velho, e agora até prisioneiro de Cristo Jesus,");
    b->dados[FILEMON].capitulos[1].versos[10] = wxT("sim, rogo-te por meu filho Onésimo, que gerei nas minhas prisões;");
    b->dados[FILEMON].capitulos[1].versos[11] = wxT("o qual outrora te foi inútil, mas agora a ti e a mim é muito útil;");
    b->dados[FILEMON].capitulos[1].versos[12] = wxT("eu to torno a enviar, a ele que é o meu próprio coração.");
    b->dados[FILEMON].capitulos[1].versos[13] = wxT("Eu bem quisera retê-lo comigo, para que em teu lugar me servisse nas prisões do evangelho;");
    b->dados[FILEMON].capitulos[1].versos[14] = wxT("mas sem o teu consentimento nada quis fazer, para que o teu benefício não fosse como por força, mas, sim, espontâneo.");
    b->dados[FILEMON].capitulos[1].versos[15] = wxT("Porque bem pode ser que ele se tenha separado de ti por algum tempo, para que o recobrasses para sempre,");
    b->dados[FILEMON].capitulos[1].versos[16] = wxT("não já como escravo, antes mais do que escravo, como irmão amado, particularmente de mim, e quanto mais de ti, tanto na carne como também no Senhor.");
    b->dados[FILEMON].capitulos[1].versos[17] = wxT("Assim pois, se me tens por companheiro, recebe-o como a mim mesmo.");
    b->dados[FILEMON].capitulos[1].versos[18] = wxT("E, se te fez algum dano, ou te deve alguma coisa, lança-o minha conta.");
    b->dados[FILEMON].capitulos[1].versos[19] = wxT("Eu, Paulo, de meu próprio punho o escrevo, eu o pagarei, para não te dizer que ainda a ti mesmo a mim te deves.");
    b->dados[FILEMON].capitulos[1].versos[20] = wxT("Sim, irmão, eu quisera regozijar-me de ti no Senhor; reanima o meu coração em Cristo.");
    b->dados[FILEMON].capitulos[1].versos[21] = wxT("Escrevo-te confiado na tua obediência, sabendo que farás ainda mais do que peço.");
    b->dados[FILEMON].capitulos[1].versos[22] = wxT("E ao mesmo tempo, prepara-me também pousada, pois espero que pelas vossas orações hei de ser concedido.");
    b->dados[FILEMON].capitulos[1].versos[23] = wxT("Saúda-te Epafras, meu companheiro de prisão em Cristo Jesus,");
    b->dados[FILEMON].capitulos[1].versos[24] = wxT("assim como Marcos, Aristarco, Demas e Lucas, meus cooperadores.");
    b->dados[FILEMON].capitulos[1].versos[25] = wxT("A graça do Senhor Jesus Cristo seja com o vosso espírito.");

}
